{"file_path": "/home/leul/Documents/w2t63/repo/frontend/src/App.js", "content": "import React from 'react';
import { BrowserRouter, Routes, Route, NavLink } from 'react-router-dom';

function Placeholder({ title }) {
  return (
    <main style={{ padding: '2rem' }}>
      <h2>{title}</h2>
      <p>Coming soon.</p>
    </main>
  );
}

function Layout({ children }) {
  const navItems = [
    { to: '/', label: 'Dashboard' },
    { to: '/residents', label: 'Residents' },
    { to: '/rooms', label: 'Rooms' },
    { to: '/maintenance', label: 'Maintenance' },
    { to: '/incidents', label: 'Incidents' },
  ];

  const linkStyle = ({ isActive }) => ({
    display: 'block',
    padding: '0.5rem 1rem',
    textDecoration: 'none',
    color: isActive ? '#0055cc' : '#333',
    fontWeight: isActive ? 'bold' : 'normal',
    background: isActive ? '#e8f0fe' : 'transparent',
    borderRadius: '4px',
  });

  return (
    <div style={{ display: 'flex', minHeight: '100vh', fontFamily: 'system-ui, sans-serif' }}>
      <nav style={{ width: '220px', borderRight: '1px solid #ddd', padding: '1rem', background: '#fafafa' }}>
        <div style={{ fontWeight: 'bold', fontSize: '1rem', marginBottom: '1.5rem', color: '#111' }}>
          ResLife Portal
        </div>
        {navItems.map(({ to, label }) => (
          <NavLink key={to} to={to} end={to === '/'} style={linkStyle}>
            {label}
          </NavLink>
        ))}
      </nav>
      <div style={{ flex: 1 }}>{children}</div>
    </div>
  );
}

export default function App() {
  return (
    <BrowserRouter>
      <Layout>
        <Routes>
          <Route path="/" element={<Placeholder title="Dashboard" />} />
          <Route path="/residents" element={<Placeholder title="Residents" />} />
          <Route path="/rooms" element={<Placeholder title="Rooms" />} />
          <Route path="/maintenance" element={<Placeholder title="Maintenance" />} />
          <Route path="/incidents" element={<Placeholder title="Incidents" />} />
        </Routes>
      </Layout>
    </BrowserRouter>
  );
}
"}

